import{_ as t,o,c as a,ag as i}from"./chunks/framework.1N8rnUr9.js";const u=JSON.parse('{"title":"Shortcodes","description":"","frontmatter":{},"headers":[],"relativePath":"features/shortcodes.md","filePath":"features/shortcodes.md","lastUpdated":null}'),s={name:"features/shortcodes.md"};function d(r,e,l,c,n,h){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="shortcodes" tabindex="-1">Shortcodes <a class="header-anchor" href="#shortcodes" aria-label="Permalink to &quot;Shortcodes&quot;">​</a></h1><p>While TubeBay handles video placement automatically based on your settings, you often need more control for specific page layouts or landing pages. Our shortcodes allow you to embed videos anywhere that supports WordPress shortcodes.</p><h2 id="the-global-video-shortcode" tabindex="-1">The Global Video Shortcode <a class="header-anchor" href="#the-global-video-shortcode" aria-label="Permalink to &quot;The Global Video Shortcode&quot;">​</a></h2><p>Use this shortcode within a single product page to display the video mapped to that specific product.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[tubebay_video]</span></span></code></pre></div><ul><li><strong>How it works:</strong> This shortcode automatically detects the current product ID and renders the linked video.</li><li><strong>Attributes:</strong> It inherits the global player settings (autoplay, controls, etc.).</li></ul><h2 id="the-specific-video-shortcode" tabindex="-1">The Specific Video Shortcode <a class="header-anchor" href="#the-specific-video-shortcode" aria-label="Permalink to &quot;The Specific Video Shortcode&quot;">​</a></h2><p>Use this to embed a specific YouTube video anywhere on your site, regardless of product mapping.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[tubebay_video id=&quot;YOUTUBE_VIDEO_ID&quot;]</span></span></code></pre></div><h3 id="attributes" tabindex="-1">Attributes: <a class="header-anchor" href="#attributes" aria-label="Permalink to &quot;Attributes:&quot;">​</a></h3><ul><li><code>id</code>: (Required) The 11-character YouTube video ID.</li><li><code>width</code>: (Optional) The width of the player (e.g., <code>100%</code> or <code>600px</code>).</li><li><code>autoplay</code>: (Optional) <code>yes</code> or <code>no</code>.</li><li><code>mute</code>: (Optional) <code>yes</code> or <code>no</code>.</li></ul><h2 id="shortcode-with-product-id" tabindex="-1">Shortcode with Product ID <a class="header-anchor" href="#shortcode-with-product-id" aria-label="Permalink to &quot;Shortcode with Product ID&quot;">​</a></h2><p>Display the video mapped to a specific product on any page (like a &quot;Video of the Day&quot; on your homepage).</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[tubebay_video product_id=&quot;123&quot;]</span></span></code></pre></div><h2 id="using-in-page-builders" tabindex="-1">Using in Page Builders <a class="header-anchor" href="#using-in-page-builders" aria-label="Permalink to &quot;Using in Page Builders&quot;">​</a></h2><p>TubeBay shortcodes are compatible with all major page builders:</p><ul><li><strong>Elementor:</strong> Use the Shortcode widget.</li><li><strong>Divi:</strong> Use the Code or Text module.</li><li><strong>Gutenberg:</strong> Use the Shortcode or Custom HTML block.</li><li><strong>Beaver Builder:</strong> Use the HTML or Text module.</li></ul>',17)])])}const g=t(s,[["render",d]]);export{u as __pageData,g as default};
